4. Implement the `Follow Camera` functionality in the `Update` method of the `CameraFollow` script.

```csharp
using UnityEngine;

[RequireComponent(typeof(Camera))]
public class CameraFollow : MonoBehaviour
{
    [SerializeField] private float speed = 500f;
    [SerializeField] private float rotationSpeed = -90f;

    private Camera targetCamera;
    private Vector3 velocity;
    private Quaternion rotation;

    private void Awake()
    {
        targetCamera = GetComponent	Camera();
    }

    private void Update()
    {
        float x = Input.GetAxisRaw("Horizontal");
        float z = Input.GetAxisRaw("Vertical");

        Vector3 move = transform.right * x + transform.forward * z;
        Vector3 target = targetCamera.transform.position + move;

        Vector3 offset = target - transform.position;
        quaternion rotate = Quaternion.LookRotation(offset);
        rotation = rotate * Time.deltaTime;

        transform.rotation = rotation;
        transform.Translate(velocity * speed * Time.deltaTime, Space.World);
    }
}
